INSERT INTO `trekking_routes` VALUES (1,'7 Days Lemosho Route','lemosho-7-days',NULL,'The Lemosho route is widely considered to be the most scenic route on Kilimanjaro, offering panoramic views on various sides of the mountain. It starts with a wild and quiet start in the rainforest before opening up to the literal roof of Africa.','Moderate-High',7,NULL,NULL,1900.00,12,'https://images.unsplash.com/photo-1549488344-1f9b8d2bd1f3?auto=format&fit=crop&w=1200&q=80','85%','[\"Exceptional Scenery\", \"Excellent Acclimatization\", \"Wild and Quiet Start\", \"Rich Biodiversity\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(2,'8 Days Lemosho Route','lemosho-8-days',NULL,'Adding an extra day for acclimatization makes the 8-day Lemosho route the gold standard for success. It offers the same stunning scenery as the 7-day version but with a gentler pace.','Moderate',8,NULL,NULL,2250.00,12,'https://images.unsplash.com/photo-1522814300958-f584e27fdf00?auto=format&fit=crop&w=2000&q=80','90%','[\"Maximum Success Rate\", \"Optimal Acclimatization\", \"Stunning Shira Plateau\", \"Remote Western Approach\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(3,'6 Days Machame Route','machame-6-days',NULL,'The \'Whiskey Route\' is the most popular path on Kilimanjaro. The 6-day version is arduous and fast-paced, suited for fit trekkers with some mountain experience.','High',6,NULL,NULL,1650.00,12,'https://images.unsplash.com/photo-1522163182402-834f871fd851?auto=format&fit=crop&w=2000&q=80','75%','[\"Dramatic Landscapes\", \"Barranco Wall Scramble\", \"Diverse Ecology\", \"Popular Scenic Choice\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(4,'7 Days Machame Route','machame-7-days',NULL,'The 7-day Machame route offers a much better success rate than the 6-day version. It includes an extra day at Karanga Valley for essential acclimatization.','Moderate-High',7,NULL,NULL,1900.00,12,'https://images.unsplash.com/photo-1544367567-0f2fcb009e0b?auto=format&fit=crop&w=1200&q=80','85%','[\"Better Acclimatization\", \"Iconic Southern Circuit\", \"Breathtaking Views\", \"Summit Success Focus\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(5,'5 Days Marangu Route','marangu-5-days',NULL,'The shortest path to the summit via huts. Arduous due to the rapid ascent, the 5-day Marangu is an intense test of willpower and physical fitness.','Hard',5,NULL,NULL,1400.00,12,'https://images.unsplash.com/photo-1522814300958-f584e27fdf00?auto=format&fit=crop&w=2000&q=80','60%','[\"Hut Accommodation\", \"Classic Route\", \"Fastest Hut Ascent\", \"Budget Friendly\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(6,'6 Days Marangu Route','marangu-6-days',NULL,'The \'Coca-Cola\' route is the only one offering hut accommodation. The 6-day version is recommended for its mandatory acclimatization day at Horombo Hut.','Moderate',6,NULL,NULL,1650.00,12,'https://images.unsplash.com/photo-1522814300958-f584e27fdf00?auto=format&fit=crop&w=2000&q=80','75%','[\"Hut Accommodation\", \"Classic Kilimanjaro Path\", \"Gentle Terrain\", \"Rainy Season Friendly\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(7,'6 Days Rongai Route','rongai-6-days',NULL,'A direct approach from the north. The 6-day Rongai is a steady climb through varied wilderness, descending via the popular Marangu trail.','Moderate-High',6,NULL,NULL,1650.00,12,'https://images.unsplash.com/photo-1542332213-9b5a5a3fad35?auto=format&fit=crop&w=1200&q=80','75%','[\"Northern Approach\", \"Less Crowded\", \"Wildlife Spottings\", \"Scenic Variety\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(8,'7 Days Rongai Route','rongai-7-days',NULL,'Approaching from the north near the Kenyan border, the Rongai route is drier and less crowded. It transitions from pine forests to cinematic alpine deserts.','Moderate',7,NULL,NULL,1900.00,12,'https://images.unsplash.com/photo-1542332213-9b5a5a3fad35?auto=format&fit=crop&w=1200&q=80','85%','[\"Remote Northern Slope\", \"Wildlife Opportunities\", \"Drier Ascent Path\", \"Quiet Wilderness\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(9,'8 Days Northern Circuit','northern-circuit-8-days',NULL,'A condensed version of the world-class Northern Circuit. Circles the high northern slopes, avoiding the crowds of the southern routes completely.','Moderate',8,NULL,NULL,2250.00,12,'https://images.unsplash.com/photo-1522814300958-f584e27fdf00?auto=format&fit=crop&w=2000&q=80','90%','[\"High Success Rate\", \"Northern Wilderness\", \"360-Degree Vistas\", \"Remote Solitude\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(10,'9 Days Northern Circuit','northern-circuit-9-days',NULL,'The newest and longest route on Kilimanjaro. It circles nearly the entire mountain, offering incredible 360-degree views and arguably the best acclimatization profile.','Moderate',9,NULL,NULL,2500.00,12,'https://images.unsplash.com/photo-1522814300958-f584e27fdf00?auto=format&fit=crop&w=2000&q=80','95%','[\"360 Degree Views\", \"Maximum Acclimatization\", \"Newest Remote Path\", \"Diverse Scenic Changes\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(11,'6 Days Umbwe Route','umbwe-6-days',NULL,'Short, steep, and hard. The Umbwe route is for experienced climbers only, offering a direct vertical ascent through spectacular terrain.','Extreme',6,NULL,NULL,1650.00,12,'https://images.unsplash.com/photo-1522814300958-f584e27fdf00?auto=format&fit=crop&w=2000&q=80','65%','[\"Fastest Direct Ascent\", \"Most Technical Path\", \"Extreme Challenge\", \"Spectacular Solitude\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(12,'7 Days Umbwe Route','umbwe-7-days',NULL,'The 7-day variation of the steep Umbwe route offers a slightly improved acclimatization window at Barranco, making the vertical push more manageable.','Extreme',7,NULL,NULL,1900.00,12,'https://images.unsplash.com/photo-1522814300958-f584e27fdf00?auto=format&fit=crop&w=2000&q=80','75%','[\"Vertical Challenge\", \"Luxury of Solitude\", \"Barranco Wall Detail\", \"High Altitude Experience\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(13,'8 Days Lemosho with Crater Camp','lemosho-8-days-crater',NULL,'Sleep within the ancient volcanic bowl of Kilimanjaro. This elite expedition includes a night at Crater Camp (5730m) near the glaciers.','Extreme',8,NULL,NULL,2750.00,12,'https://images.unsplash.com/photo-1549488344-1f9b8d2bd1f3?auto=format&fit=crop&w=1200&q=80','85%','[\"Sleep in the Crater\", \"Elite Adventure\", \"Touch the Glaciers\", \"Sunrise at the Peak\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(14,'9 Days Northern Circuit & Crater','northern-circuit-9-days-crater',NULL,'The ultimate Kilimanjaro experience. Combines the best-acclimatized route with a night inside the crater. Experience the mountain in its full glory.','Extreme',9,NULL,NULL,3000.00,12,'https://images.unsplash.com/photo-1522814300958-f584e27fdf00?auto=format&fit=crop&w=2000&q=80','90%','[\"360 Degree Northern Circuit\", \"Crater Overnight\", \"Unrivaled Success Rate\", \"Glacial Sleeping Experience\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(15,'3 Days Mount Meru Climb','mt-meru-3-days',NULL,'Mount Meru is the perfect warm-up for Kilimanjaro or a stunning stand-alone peak. This 3-day trek is fast-paced but scenically rewarding.','Moderate',3,NULL,NULL,850.00,12,'https://images.unsplash.com/photo-1549488344-1f9b8d2bd1f3?auto=format&fit=crop&w=1200&q=80','85%','[\"Walking Safari\", \"Dramatic Ash Cone\", \"View of Kilimanjaro\", \"Arusha National Park\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]'),(16,'4 Days Mount Meru Climb','mt-meru-4-days',NULL,'The recommended Meru itinerary. Includes an extra day at Saddle Hut for better acclimatization and higher success at the Socialist Peak.','Moderate',4,NULL,NULL,950.00,12,'https://images.unsplash.com/photo-1549488344-1f9b8d2bd1f3?auto=format&fit=crop&w=1200&q=80','95%','[\"Optimal Acclimatization\", \"Ash Cone Vistas\", \"Kilimanjaro Silhouettes\", \"Rich Wildlife\"]','2026-03-23 12:20:20','2026-03-23 12:20:20','[\"2 Nights Hotel Accommodation (Moshi\\/Arusha)\",\"All Kilimanjaro National Park Fees\",\"Professional Certified Mountain Guides\",\"Personalized Mountain Cook & Assistant\",\"Traceable Oxygen & Pulse Oximeters\",\"All Meals on Mountain (B, L, D)\",\"High-Quality Mountain Tents & Mats\",\"Fair Crew Wages & Comprehensive Insurance\"]','[\"International & Domestic Flights\",\"Tanzania Entry Visa Fees\",\"Tips for Mountain Crew (Recommended)\",\"Personal Trekking Gear & Sleeping Bags\",\"Travel & Medical Insurance\",\"Items of a Personal Nature\"]');
